import React, { useState } from 'react';
import { Calendar, Users, Award } from 'lucide-react';
import './CompetitionsPage.css';

const competitionsData = [
  {
    year: '2022',
    panitia: '/ESC 22-23.jpeg',
    events: [
      { id: 'drone', title: 'Drone', bg: '/WorkshopDrone.jpg', desc: 'Kompetisi drone racing dan misi otomatis.' },
      { id: 'wf', title: 'Workshop Festival', bg: '/WorkshopDrone.jpg', desc: 'Ajang kreativitas teknologi.' },
      { id: 'rcv', title: 'Robot Computer Vision', bg: '/WorkshopDrone.jpg', desc: 'Robot berbasis computer vision.' },
    ],
  },
  {
    year: '2025',
    panitia: '/ESC 24-25.jpeg',
    events: [
      { id: 'drone', title: 'Drone', bg: '/WorkshopDrone.jpg', desc: 'Kompetisi drone racing dan misi otomatis yang menguji kemampuan navigasi dan kontrol UAV secara presisi.' },
      { id: 'wf', title: 'Workshop Festival', bg: '/WorkshopDrone.jpg', desc: 'Ajang unjuk kreativitas dan inovasi teknologi oleh tim asisten laboratorium.' },
      { id: 'gripper', title: 'Robot Gripper', bg: '/WorkshopDrone.jpg', desc: 'Robot gripper otomatis yang dirancang untuk memindahkan dan menyortir objek dengan akurasi tinggi.' },
      { id: 'psk', title: 'Proyek Sistem Komputer', bg: '/WorkshopDrone.jpg', desc: 'Kompetisi perancangan sistem komputer terintegrasi mulai dari hardware hingga software aplikasi.' },
    ],
  },
  {
    year: '2026',
    panitia: '/ESC 24-25.jpeg',
    isLive: true,
    events: [
      { id: 'drone', title: 'Drone', bg: '/WorkshopDrone.jpg', desc: 'Kompetisi drone racing.' },
      { id: 'wf', title: 'Workshop Festival', bg: '/WorkshopDrone.jpg', desc: 'Ajang inovasi teknologi.' },
      { id: 'triathlon', title: 'Triathlon Robot', bg: '/WorkshopDrone.jpg', desc: 'Robot multi challenge.' },
    ],
  },
];

function EventCard({ event, index }) {
  return (
    <div className="event-card fade-in">
      <img src={event.bg} alt={event.title} className="event-img" />

      <div className="event-overlay" />

      <div className="event-content">
        <span className="event-number">
          {String(index + 1).padStart(2, '0')}
        </span>

        <div>
          <h3>{event.title}</h3>
          <p>{event.desc}</p>
          <div className="event-line" />
        </div>
      </div>
    </div>
  );
}

function YearSection({ data }) {
  return (
    <div className="year-section fade-in">
      <div className="year-header">
        <h2>ESC {data.year}</h2>
        {data.isLive && <span className="badge-live">● Live</span>}
      </div>

      <div className="panitia">
        <img src={data.panitia} alt="" />
      </div>

      <div className="events-grid">
        {data.events.map((event, i) => (
          <EventCard key={event.id} event={event} index={i} />
        ))}
      </div>
    </div>
  );
}

export default function CompetitionsPage() {
  return (
    <div className="page">
      <div className="hero fade-in">
        <h1>ESC Competition</h1>
        <p>Electronic Student Competition</p>

        <div className="stats">
          <div><Calendar size={16} /> 3+ Tahun</div>
          <div><Award size={16} /> 10+ Lomba</div>
          <div><Users size={16} /> 100+ Tim</div>
        </div>
      </div>

      {competitionsData.map((data) => (
        <YearSection key={data.year} data={data} />
      ))}
    </div>
  );
}
